const current = $input.first().json;
const original = $('Loop Over Strategies').first().json;

const sharpeDrop = original.sharpeRatio > 0 
  ? (Number(original.sharpeRatio) - Number(current.sharpeRatio)) / Number(original.sharpeRatio) 
  : 0;
const winRateDrop = Number(original.winRate) - Number(current.winRate);

const degraded = sharpeDrop > 0.20 || winRateDrop > 0.10;

return [{
  json: {
    strategyId: current.strategyId,
    strategyName: original.name,
    degraded,
    sharpeDrop: (sharpeDrop * 100).toFixed(1) + '%',
    winRateDrop: (winRateDrop * 100).toFixed(1) + '%',
    currentSharpe: current.sharpeRatio,
    originalSharpe: original.sharpeRatio,
    currentWinRate: current.winRate,
    originalWinRate: original.winRate,
  }
}];

